import React, { useState, useEffect } from "react";
import axios from "axios";

const API_URL = "http://127.0.0.1:5000";

function ImageDetector() {
  const [file, setFile] = useState(null);
  const [result, setResult] = useState(null);
  const [error, setError] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [preview, setPreview] = useState(null);
  const [isDragOver, setIsDragOver] = useState(false);
  const [progress, setProgress] = useState(0);

  const handleFileChange = (selectedFile) => {
    if (!selectedFile) return;
    setFile(selectedFile);
    setResult(null);
    setError("");
    setPreview(URL.createObjectURL(selectedFile));
  };

  const handleClear = () => {
    setFile(null);
    setResult(null);
    setError("");
    setPreview(null);
    setProgress(0);
  };

  const handleSubmit = async (event) => {
    event.preventDefault();
    if (!file) return;

    const formData = new FormData();
    formData.append("file", file);
    setIsLoading(true);
    setProgress(0);

    // Simulate progress for better UX
    const interval = setInterval(() => {
      setProgress((prev) => (prev < 90 ? prev + 10 : prev));
    }, 300);

    try {
      const response = await axios.post(`${API_URL}/predict/image`, formData);
      setProgress(100);
      setResult(response.data);
    } catch (err) {
      setError(
        "Analysis failed. Please ensure the backend is running and the file is valid."
      );
    } finally {
      clearInterval(interval);
      setIsLoading(false);
    }
  };

  // Drag and Drop handlers
  const handleDragOver = (e) => {
    e.preventDefault();
    setIsDragOver(true);
  };
  const handleDragLeave = (e) => {
    e.preventDefault();
    setIsDragOver(false);
  };
  const handleDrop = (e) => {
    e.preventDefault();
    setIsDragOver(false);
    const droppedFile = e.dataTransfer.files[0];
    if (
      droppedFile &&
      (droppedFile.type === "image/jpeg" || droppedFile.type === "image/png")
    ) {
      handleFileChange(droppedFile);
    }
  };

  return (
    <div className="detector-container">
      <h2>🖼️ Image Deepfake Detector</h2>

      {!result && (
        <div
          className={`drop-zone ${isDragOver ? "drag-over" : ""}`}
          onClick={() => document.getElementById("file-upload").click()}
          onDragOver={handleDragOver}
          onDragLeave={handleDragLeave}
          onDrop={handleDrop}
        >
          <input
            id="file-upload"
            type="file"
            onChange={(e) => handleFileChange(e.target.files[0])}
            accept="image/jpeg,image/png"
          />
          <p>Drag & Drop an Image Here</p>
          <small>or click to select</small>
        </div>
      )}

      {file && (
        <div className="preview-container">
          <img src={preview} alt="Selected Preview" />
          <p style={{ color: "var(--text-muted)", marginTop: "0.5rem" }}>
            {file.name}
          </p>
        </div>
      )}

      <div className="button-group">
        {!result && (
          <button
            type="button"
            className="btn"
            onClick={handleSubmit}
            disabled={isLoading || !file}
          >
            {isLoading ? "Analyzing..." : "Analyze Image"}
          </button>
        )}
        {(result || error) && (
          <button type="button" className="btn btn-clear" onClick={handleClear}>
            Clear & Start Over
          </button>
        )}
      </div>

      {isLoading && (
        <div className="progress-bar">
          <div
            className="progress-bar-inner"
            style={{ width: `${progress}%` }}
          ></div>
        </div>
      )}
      {error && (
        <p style={{ color: "var(--danger-color)", textAlign: "center" }}>
          {error}
        </p>
      )}

      {result && (
        <div
          className={`result-card ${
            result.result === "REAL" ? "result-real" : "result-deepfake"
          }`}
        >
          <h4>{result.result}</h4>
          <p>
            The model's confidence score for this classification is **
            {(result.confidence * 100).toFixed(2)}%**.
          </p>
        </div>
      )}
    </div>
  );
}

export default ImageDetector;
